// 1. Get the raw text content from the OpenAI extraction node
// Note: We access .choices[0].message.content because it's a Chat Completion
const rawContent = $input.first().json.choices[0].message.content
const parsed = JSON.parse(rawContent);

// 2. Reference the correct Trigger name (Wati Trigger1)
const triggerNode = $('Wati Trigger').first();
const phone = triggerNode.json.waId || triggerNode.json.from || 'unknown';
const senderName = triggerNode.json.senderName || 'User';

// 3. Create the expense object
const now = new Date();
const expenseRow = {
  timestamp: now.toISOString(),
  phone: phone,
  senderName: senderName,
  vendor: parsed.vendor || parsed.merchant || 'Unknown Vendor',
  amount: parsed.amount || parsed.total || 0,
  currency: parsed.currency || 'INR',
  date: parsed.date || now.toISOString().split('T')[0],
  category: parsed.category || 'Other',
  description: parsed.description || ''
};

return { json: expenseRow };

// ── Build Monthly Report ──────────────────────────────────────────
// Reads all rows, filters to current month, aggregates by category.

const allRows = $input.all();
const now = new Date();
const currentMonth = now.toISOString().substring(0, 7); // YYYY-MM
const callerPhone = $('Wati Trigger').first().json.waId

// Filter only this month & this user's expenses
const rows = allRows.filter(r => {
  const rowMonth = r.json.month || (r.json.timestamp || '').substring(0, 7);
  const rowPhone = r.json.phone || '';
  return rowMonth === currentMonth && rowPhone === callerPhone;
});

const monthLabel = now.toLocaleString('default', { month: 'long', year: 'numeric' });

if (!rows || rows.length === 0) {
  return [{ json: { reportText: `📊 No expenses recorded for *${monthLabel}* yet.\n\nSnap a receipt photo to start tracking!` } }];
}

// Aggregate by category
const categoryTotals = {};
let grandTotal = 0;
let currency = 'USD';

for (const row of rows) {
  const cat = row.json.category || 'Other';
  const amt = parseFloat(row.json.amount) || 0;
  currency = row.json.currency || currency;
  categoryTotals[cat] = (categoryTotals[cat] || 0) + amt;
  grandTotal += amt;
}

// Build formatted WhatsApp message with visual bars
const lines = [`📊 *Monthly Expense Report*`, `📅 *${monthLabel}*`, ''];

const sorted = Object.entries(categoryTotals).sort((a, b) => b[1] - a[1]);
for (const [cat, total] of sorted) {
  const pct = grandTotal > 0 ? ((total / grandTotal) * 100) : 0;
  const filledBars = Math.round(pct / 10);
  const bar = '█'.repeat(filledBars) + '░'.repeat(10 - filledBars);
  lines.push(`${bar} *${cat}*`);
  lines.push(`  ${currency} ${total.toFixed(2)}  (${pct.toFixed(1)}%)`);
  lines.push('');
}

lines.push(`━━━━━━━━━━━━━━━━━━`);
lines.push(`💰 *Total Spent: ${currency} ${grandTotal.toFixed(2)}*`);
lines.push(`🧾 *Receipts logged: ${rows.length}*`);
lines.push('');
lines.push('Snap a receipt photo to log a new expense!');

return [{ json: { reportText: lines.join('\n'), grandTotal, currency, count: rows.length } }];

// Get the item and its binary data reference
const item = $input.first();
const binaryPropertyName = 'data'; // Ensure this matches your binary field name
const binaryData = item.binary?.[binaryPropertyName];

if (!binaryData) {
  throw new Error(`No binary data found in property "${binaryPropertyName}".`);
}

// Retrieve the actual file buffer from n8n's storage
const buffer = await this.helpers.getBinaryDataBuffer(0, binaryPropertyName);

// Convert that buffer into a real Base64 string
const base64String = buffer.toString('base64');
const mimeType = binaryData.mimeType || 'image/jpeg';

return {
  json: {
    mimeType: mimeType,
    // This will now contain the ACTUAL image code, not "filesystem-v2"
    dataUrl: `data:${mimeType};base64,${base64String}`
  }
};

